define i1 @branch_sgt_zero_to_x_lt_y_true(i32 %x, i32 %y) {
entry:
  %sub = sub nsw i32 %y, %x
  %cond = icmp sgt i32 %sub, 0
  br i1 %cond, label %then, label %else

then:
  ret i1 true

else:
  ret i1 false
}

